$total = 0;

$init = function () use (&$input, &$total) {
  $al = count($input);

  for ($i = 0; $i < $al; $i++) {
    $str = &$input[$i];
    $sl = strlen($str);

    for ($k = 0; $k < $sl; $k++) {
      $b = $i + 1 < $al ? $input[$i + 1][$k] : "";
      $t = $i - 1 >= 0 ? $input[$i - 1][$k] : "";
      $r = $k + 1 < $sl ? $str[$k + 1] : "";
      $l = $k - 1 >= 0 ? $str[$k - 1] : "";
      $br = $i + 1 < $al && $k + 1 < $sl ? $input[$i + 1][$k + 1] : "";
      $bl = $i + 1 < $al && $k - 1 >= 0 ? $input[$i + 1][$k - 1] : "";
      $tr = $i - 1 >= 0 && $k + 1 < $sl ? $input[$i - 1][$k + 1] : "";
      $tl = $k - 1 >= 0 && $i - 1 >= 0 ? $input[$i - 1][$k - 1] : "";

      if ($str[$k] !== "@") {
        continue;
      }

      if (substr_count("$b$t$r$l$br$bl$tr$tl", "@") < 4) {
        $total++;
      }
    }
  }
};

$init();
var_dump($total);
